What does the following program print?

```cpp
#include <iostream>

class Gauge {
private:
    int m_reading{ 10 };

public:
    int  getReading() const { return m_reading; }
    void setReading(int r)  {
        if (r < 0) r = 0;
        m_reading = r;
    }
};

int main() {
    Gauge g;
    g.setReading(-5);
    std::cout << g.getReading() << '\n';
    g.setReading(20);
    std::cout << g.getReading() << '\n';
    return 0;
}
```

